sub handle_register {
    my ($cgi) = @_;

    my $username         = $cgi->param('username')         // '';
    my $password         = $cgi->param('password')         // '';
    my $password_confirm = $cgi->param('password_confirm') // '';

    # Input validation
    my @errors;

    if ($username !~ /\A[a-zA-Z0-9_]{3,64}\z/) {
        push @errors, "Username must be 3-64 alphanumeric characters or underscores.";
    }

    if (length($password) < 12) {
        push @errors, "Password must be at least 12 characters long.";
    }

    if (length($password) > 128) {
        push @errors, "Password must not exceed 128 characters.";
    }

    if ($password ne $password_confirm) {
        push @errors, "Passwords do not match.";
    }

    # Check password complexity
    unless ($password =~ /[A-Z]/ && $password =~ /[a-z]/ && $password =~ /[0-9]/) {
        push @errors, "Password must contain uppercase, lowercase, and numeric characters.";
    }

    if (@errors) {
        my $error_html = join("<br>", map { encode_entities($_) } @errors);
        print "<h1>Registration Error</h1><p>$error_html</p>";
        print '<p><a href="?">Back</a></p>';
        return;
    }

    # Hash password with bcrypt (NOT MD5)
    my $hashed_password = hash_password_bcrypt($password);

    eval {
        my $dbh = get_dbh();

        # Check if username already exists
        my $check_sth = $dbh->prepare("SELECT COUNT(*) FROM users WHERE username = ?");
        $check_sth->execute($username);
        my ($exists) = $check_sth->fetchrow_array();
        $check_sth->finish();

        if ($exists) {
            # Use generic message to prevent username enumeration
            print "<h1>Registration Error</h1>";
            print "<p>Unable to complete registration. Please try again.</p>";
            print '<p><a href="?">Back</a></p>';
            $dbh->disconnect();
            return;
        }

        my $sth = $dbh->prepare(
            "INSERT INTO users (username, password_hash, hash_type, created_at) VALUES (?, ?, 'bcrypt', NOW())"
        );
        $sth->execute($username, $hashed_password);
        $sth->finish();
        $dbh->disconnect();

        my $safe_username = encode_entities($username);
        print "<h1>Registration Successful</h1>";
        print "<p>User '$safe_username' has been registered with bcrypt password hashing.</p>";
        print '<p><a href="?">Back</a></p>';
    };

    if ($@) {
        # Log the actual error server-side, show generic message to user
        warn "Registration error: $@";
        print "<h1>Registration Error</h1>";
        print "<p>An internal error occurred. Please try again later.</p>";
        print '<p><a href="?">Back</a></p>';
    }
}

