sub handle_change_password {
    my ($cgi) = @_;

    # In production, verify the user is authenticated via session
    my $username     = $cgi->param('username')     // '';
    my $old_password = $cgi->param('old_password') // '';
    my $new_password = $cgi->param('new_password') // '';

    if (length($new_password) < 12) {
        print "<h1>Error</h1><p>New password must be at least 12 characters.</p>";
        print '<p><a href="?">Back</a></p>';
        return;
    }

    eval {
        my $dbh = get_dbh();

        my $sth = $dbh->prepare(
            "SELECT password_hash, hash_type FROM users WHERE username = ?"
        );
        $sth->execute($username);
        my ($stored_hash, $hash_type) = $sth->fetchrow_array();
        $sth->finish();

        unless ($stored_hash) {
            $dbh->disconnect();
            print "<h1>Error</h1><p>Password change failed.</p>";
            print '<p><a href="?">Back</a></p>';
            return;
        }

        my $authenticated = verify_and_migrate_password(
            $username, $old_password, $stored_hash, $hash_type
        );

        unless ($authenticated) {
            $dbh->disconnect();
            print "<h1>Error</h1><p>Current password is incorrect.</p>";
            print '<p><a href="?">Back</a></p>';
            return;
        }

        # Hash new password with bcrypt
        my $new_hash = hash_password_bcrypt($new_password);

        my $update_sth = $dbh->prepare(
            "UPDATE users SET password_hash = ?, hash_type = 'bcrypt' WHERE username = ?"
        );
        $update_sth->execute($new_hash, $username);
        $update_sth->finish();
        $dbh->disconnect();

        print "<h1>Password Changed</h1>";
        print "<p>Your password has been updated successfully with bcrypt hashing.</p>";
        print '<p><a href="?">Back</a></p>';
    };

    if ($@) {
        warn "Password change error: $@";
        print "<h1>Error</h1>";
        print "<p>An internal error occurred. Please try again later.</p>";
        print '<p><a href="?">Back</a></p>';
    }
}

